using System;\nusing System.Drawing;\nusing System.Windows.Forms;\nusing Emgu.CV;\nusing Emgu.CV.CvEnum;\nusing Emgu.CV.Structure;\n\nnamespace YourNamespace\n{\n    public class RedPointCleaner\n    {\n        public static void RemoveRedPoints(string inputImagePath, string outputImagePath)\n        {\n            // Load the image\n            Mat img = CvInvoke.Imread(inputImagePath, ImreadModes.Color);\n\n            // Convert to HSV color space\n            Mat hsvImg = new Mat();\n            CvInvoke.CvtColor(img, hsvImg, ColorConversion.Bgr2Hsv);\n\n            // Define the range of red colors in HSV\n            var lowerRed1 = new Scalar(0, 100, 100); // Lower bound for red\n            var upperRed1 = new Scalar(10, 255, 255); // Upper bound for red\n            var lowerRed2 = new Scalar(160, 100, 100); // Lower bound for red\n            var upperRed2 = new Scalar(180, 255, 255); // Upper bound for red\n\n            // Create masks for red color\n            Mat mask1 = new Mat();\n            Mat mask2 = new Mat();\n            CvInvoke.InRange(hsvImg, lowerRed1, upperRed1, mask1);\n            CvInvoke.InRange(hsvImg, lowerRed2, upperRed2, mask2);\n\n            // Combine masks\n            Mat combinedMask = new Mat();\n            CvInvoke.Add(mask1, mask2, combinedMask);\n\n            // Invert the mask to remove red points\n            Mat invertedMask = new Mat();\n            CvInvoke.BitwiseNot(combinedMask, invertedMask);\n\n            // Apply the inverted mask to the original image\n            Mat resultImg = new Mat();\n            CvInvoke.BitwiseAnd(img, img, resultImg, invertedMask);\n\n            // Save the modified image\n            CvInvoke.Imwrite(outputImagePath, resultImg);\n        }\n\n        // Example usage in WinForms application\n        public static void Main()\n        {\n            RemoveRedPoints("input_image_path.jpg", "output_image_path.jpg"); // Replace with actual paths\n        }\n    }\n}